firmware_template.source:
#include "ina219.h"
#include <Wire.h>
static Adafruit_INA219 ina;
static float _busV=0,_shuntV=0,_mA=0,_mW=0;
static unsigned long _last=0;
void ina219_setup() {
  Wire.begin();
  if (!ina.begin()) { Serial.println("[ina219] Init failed!"); return; }
  ina.setCalibration_32V_2A();
  Serial.println("[ina219] OK");
}
void ina219_loop() {
  if (millis()-_last < 500) return;
  _last = millis();
  _busV = ina.getBusVoltage_V();
  _shuntV = ina.getShuntVoltage_mV();
  _mA = ina.getCurrent_mA();
  _mW = ina.getPower_mW();
  Serial.printf("[ina219] %.2fV %.1fmA %.1fmW\n",_busV,_mA,_mW);
}
float ina219_get_bus_voltage(){return _busV;}
float ina219_get_shunt_voltage(){return _shuntV;}
float ina219_get_current_mA(){return _mA;}
float ina219_get_power_mW(){return _mW;}
